+fn strip_cr_before_nl(buf: &mut String) {
+    let buf_bytes = buf.as_bytes();
+    let len = buf_bytes.len();
+    if len >= 2 && buf_bytes[len - 2] == b'\r' && buf_bytes[len - 1] == b'\n' {
